import{c as o,Q as e,j as r,m as t}from"./chunks/framework.DS5OPS01.js";const b=JSON.parse('{"title":"FAQ","description":"","frontmatter":{"title":"FAQ"},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),i={name:"faq.md"};function l(d,a,n,s,h,c){return e(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="blkops-需要-root-吗" tabindex="-1">blkops 需要 root 吗？ <a class="header-anchor" href="#blkops-需要-root-吗" aria-label="Permalink to &quot;blkops 需要 root 吗？&quot;">​</a></h2><p>是的，blkops 直接操作 block 设备，通常需要 root 权限。</p><hr><h2 id="支持哪些-android-版本" tabindex="-1">支持哪些 Android 版本？ <a class="header-anchor" href="#支持哪些-android-版本" aria-label="Permalink to &quot;支持哪些 Android 版本？&quot;">​</a></h2><p>blkops 不依赖 Android 版本，只要能访问 <code>/dev/block</code> 即可。</p><hr><h2 id="能否用于量产-商业项目" tabindex="-1">能否用于量产 / 商业项目？ <a class="header-anchor" href="#能否用于量产-商业项目" aria-label="Permalink to &quot;能否用于量产 / 商业项目？&quot;">​</a></h2><p>可以，blkops 使用 <strong>Apache-2.0 协议</strong>，允许商用。</p><hr><h2 id="构建失败怎么办" tabindex="-1">构建失败怎么办？ <a class="header-anchor" href="#构建失败怎么办" aria-label="Permalink to &quot;构建失败怎么办？&quot;">​</a></h2><ul><li>确认 Rust ≥ 1.70</li><li>确认 Android NDK 路径正确</li><li>Windows 需安装 VS 2022 C++ 工具链</li></ul><hr><h2 id="是否支持-macos" tabindex="-1">是否支持 macOS？ <a class="header-anchor" href="#是否支持-macos" aria-label="Permalink to &quot;是否支持 macOS？&quot;">​</a></h2><p>目前主要支持 Windows / Linux，macOS 暂未测试。</p>',15)])])}const m=o(i,[["render",l]]);export{b as __pageData,m as default};
